import { useState } from 'react'
import { Plus, Edit, Trash2, Ticket } from 'lucide-react'
import { Button } from '@/components/ui/button'
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from '@/components/ui/dialog'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import { Switch } from '@/components/ui/switch'
import { Badge } from '@/components/ui/badge'
import useCouponStore, { Coupon } from '@/stores/useCouponStore'
import { useToast } from '@/hooks/use-toast'

export default function AdminCoupons() {
  const { coupons, addCoupon, updateCoupon, deleteCoupon } = useCouponStore()
  const { toast } = useToast()

  const [isFormOpen, setIsFormOpen] = useState(false)
  const [editingId, setEditingId] = useState<string | null>(null)

  const [formData, setFormData] = useState<Partial<Coupon>>({
    code: '',
    type: 'percentage',
    value: 0,
    isActive: true,
    expirationDate: '',
    isWelcomeCoupon: false,
  })

  const handleOpenNew = () => {
    setFormData({
      code: '',
      type: 'percentage',
      value: 0,
      isActive: true,
      expirationDate: '',
      isWelcomeCoupon: false,
    })
    setEditingId(null)
    setIsFormOpen(true)
  }

  const handleOpenEdit = (coupon: Coupon) => {
    setFormData({ ...coupon })
    setEditingId(coupon.id)
    setIsFormOpen(true)
  }

  const handleSave = () => {
    if (!formData.code?.trim() || !formData.value) {
      toast({
        title: 'Dados inválidos',
        description: 'Por favor, preencha o código e o valor do desconto.',
        variant: 'destructive',
      })
      return
    }

    if (editingId) {
      updateCoupon(editingId, formData)
      toast({ title: 'Cupom atualizado', description: 'As alterações foram salvas com sucesso.' })
    } else {
      addCoupon(formData as Omit<Coupon, 'id' | 'usageCount'>)
      toast({
        title: 'Cupom criado',
        description: 'O novo cupom de desconto está pronto para uso.',
      })
    }
    setIsFormOpen(false)
  }

  const handleDelete = (id: string) => {
    if (confirm('Deseja realmente excluir este cupom permanentemente?')) {
      deleteCoupon(id)
      toast({ title: 'Cupom removido', description: 'O cupom foi excluído do sistema.' })
    }
  }

  return (
    <div className="animate-fade-in">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
        <div>
          <h1 className="text-3xl font-heading font-bold mb-1">Cupons de Desconto</h1>
          <p className="text-muted-foreground">Gerencie promoções e descontos dinâmicos da loja.</p>
        </div>
        <Button onClick={handleOpenNew}>
          <Plus className="w-4 h-4 mr-2" />
          Novo Cupom
        </Button>
      </div>

      <div className="bg-card rounded-xl border shadow-subtle overflow-hidden">
        <Table>
          <TableHeader className="bg-muted/50">
            <TableRow>
              <TableHead>Código</TableHead>
              <TableHead>Desconto</TableHead>
              <TableHead>Validade</TableHead>
              <TableHead>Status</TableHead>
              <TableHead>Uso</TableHead>
              <TableHead className="text-right">Ações</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {coupons.length === 0 ? (
              <TableRow>
                <TableCell
                  colSpan={6}
                  className="text-center py-12 text-muted-foreground flex-col items-center justify-center"
                >
                  <Ticket className="w-8 h-8 mx-auto mb-3 text-muted-foreground/50" />
                  Nenhum cupom cadastrado.
                </TableCell>
              </TableRow>
            ) : (
              coupons.map((coupon) => (
                <TableRow key={coupon.id}>
                  <TableCell className="font-bold text-primary">
                    <div className="flex items-center gap-2">
                      {coupon.code}
                      {coupon.isWelcomeCoupon && <Badge variant="secondary">Boas-Vindas</Badge>}
                    </div>
                  </TableCell>
                  <TableCell className="font-medium">
                    {coupon.type === 'percentage'
                      ? `${coupon.value}%`
                      : `R$ ${coupon.value.toFixed(2).replace('.', ',')}`}
                  </TableCell>
                  <TableCell className="text-muted-foreground">
                    {coupon.expirationDate
                      ? new Date(
                          new Date(coupon.expirationDate).getTime() +
                            new Date().getTimezoneOffset() * 60000,
                        ).toLocaleDateString('pt-BR')
                      : 'Vitalício'}
                  </TableCell>
                  <TableCell>
                    <span
                      className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-medium ${
                        coupon.isActive
                          ? 'bg-green-500/10 text-green-600'
                          : 'bg-muted text-muted-foreground'
                      }`}
                    >
                      {coupon.isActive ? 'Ativo' : 'Inativo'}
                    </span>
                  </TableCell>
                  <TableCell className="text-muted-foreground">{coupon.usageCount} vezes</TableCell>
                  <TableCell className="text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="secondary"
                        size="icon"
                        className="h-8 w-8"
                        onClick={() => handleOpenEdit(coupon)}
                        title="Editar Cupom"
                      >
                        <Edit className="w-4 h-4" />
                      </Button>
                      <Button
                        variant="destructive"
                        size="icon"
                        className="h-8 w-8"
                        onClick={() => handleDelete(coupon.id)}
                        title="Excluir Cupom"
                      >
                        <Trash2 className="w-4 h-4" />
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </div>

      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingId ? 'Editar Cupom' : 'Criar Novo Cupom'}</DialogTitle>
            <DialogDescription>
              Defina as regras e o código para o seu cupom de desconto.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="code">Código do Cupom</Label>
                <Input
                  id="code"
                  value={formData.code}
                  onChange={(e) =>
                    setFormData({
                      ...formData,
                      code: e.target.value.toUpperCase().replace(/\s/g, ''),
                    })
                  }
                  placeholder="Ex: PROMO20"
                  className="uppercase"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="expirationDate">Data de Validade (Opcional)</Label>
                <Input
                  id="expirationDate"
                  type="date"
                  value={formData.expirationDate || ''}
                  onChange={(e) => setFormData({ ...formData, expirationDate: e.target.value })}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="type">Tipo de Desconto</Label>
                <Select
                  value={formData.type}
                  onValueChange={(v: 'percentage' | 'fixed') =>
                    setFormData({ ...formData, type: v })
                  }
                >
                  <SelectTrigger id="type">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="percentage">Porcentagem (%)</SelectItem>
                    <SelectItem value="fixed">Fixo (R$)</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="value">Valor</Label>
                <Input
                  id="value"
                  type="number"
                  min="0"
                  step="0.01"
                  value={formData.value || ''}
                  onChange={(e) =>
                    setFormData({ ...formData, value: parseFloat(e.target.value) || 0 })
                  }
                  placeholder="0.00"
                />
              </div>
            </div>

            <div className="flex items-center justify-between rounded-lg border p-4 bg-muted/30">
              <div className="space-y-0.5">
                <Label className="text-base cursor-pointer" htmlFor="welcome">
                  Cupom de Boas-Vindas
                </Label>
                <p className="text-sm text-muted-foreground">
                  Este cupom será enviado automaticamente para novos usuários cadastrados.
                </p>
              </div>
              <Switch
                id="welcome"
                checked={formData.isWelcomeCoupon}
                onCheckedChange={(c) => setFormData({ ...formData, isWelcomeCoupon: c })}
              />
            </div>

            <div className="flex items-center justify-between rounded-lg border p-4 bg-muted/30">
              <div className="space-y-0.5">
                <Label className="text-base cursor-pointer" htmlFor="status">
                  Status do Cupom
                </Label>
                <p className="text-sm text-muted-foreground">
                  Cupons inativos não podem ser resgatados em compras.
                </p>
              </div>
              <Switch
                id="status"
                checked={formData.isActive}
                onCheckedChange={(c) => setFormData({ ...formData, isActive: c })}
              />
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setIsFormOpen(false)}>
              Cancelar
            </Button>
            <Button onClick={handleSave}>Salvar Cupom</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}
